import os
import shutil
import tarfile
import zipfile
from subprocess import call

def backup_directory(source_dir, output_format):
    if not os.path.exists(source_dir):
        print(f"Directory {source_dir} does not exist.")
        return

    base_name = os.path.basename(source_dir)
    output_file = f"{base_name}.{output_format}"

    try:
        if output_format == 'tar.gz':
            with tarfile.open(output_file, "w:gz") as tar:
                tar.add(source_dir, arcname=base_name)
        elif output_format == 'tar.bz2':
            with tarfile.open(output_file, "w:bz2") as tar:
                tar.add(source_dir, arcname=base_name)
        elif output_format == 'zip':
            with zipfile.ZipFile(output_file, 'w', zipfile.ZIP_DEFLATED) as zipf:
                for root, dirs, files in os.walk(source_dir):
                    for file in files:
                        zipf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), source_dir))
        elif output_format == '7z':
            call(['7z', 'a', output_file, source_dir])
        else:
            print(f"Unsupported format: {output_format}")
            return

        print(f"Backup created successfully: {output_file}")
    except Exception as e:
        print(f"Error creating backup: {e}")

if __name__ == "__main__":
    import argparse
    parser = argparse.ArgumentParser(description="Quick backup script for user directories.")
    parser.add_argument("source_dir", type=str, help="Path to the directory to backup")
    parser.add_argument("output_format", type=str, choices=['tar.gz', 'tar.bz2', 'zip', '7z'], help="Desired output format")

    args = parser.parse_args()
    backup_directory(args.source_dir, args.output_format)